window.KnowledgeBase = {
    subjects: subjects,
    tree: tree,
    details: details,
    searchIndex: searchIndex,
    totalKP: 541,

    // 获取知识点详情
    getKP: function(id) {
        return details[id] || null;
    },

    // 搜索知识点
    search: function(query) {
        if (!query || query.trim().length === 0) return [];
        var q = query.trim().toLowerCase();
        var results = [];
        for (var i = 0; i < searchIndex.length; i++) {
            if (searchIndex[i].text.indexOf(q) !== -1) {
                results.push(searchIndex[i]);
            }
        }
        return results;
    },

    // 获取某学科的知识点列表（扁平化）
    getKPsBySubject: function(subjectId) {
        var results = [];
        var subj = tree[subjectId];
        if (!subj) return results;
        for (var i = 0; i < subj.modules.length; i++) {
            var mod = subj.modules[i];
            for (var j = 0; j < mod.units.length; j++) {
                var unit = mod.units[j];
                for (var k = 0; k < unit.knowledge_points.length; k++) {
                    results.push(unit.knowledge_points[k]);
                }
            }
        }
        return results;
    },

    // 获取某年级阶段的知识点列表
    getKPsByPhase: function(phase) {
        var results = [];
        for (var i = 0; i < searchIndex.length; i++) {
            if (searchIndex[i].phase === phase) {
                results.push(searchIndex[i]);
            }
        }
        return results;
    },

    // 获取某学科+年级的知识点
    getKPsBySubjectAndPhase: function(subjectId, phase) {
        var results = [];
        var subj = tree[subjectId];
        if (!subj) return results;
        for (var i = 0; i < subj.modules.length; i++) {
            var mod = subj.modules[i];
            for (var j = 0; j < mod.units.length; j++) {
                var unit = mod.units[j];
                if (unit.phase === phase) {
                    for (var k = 0; k < unit.knowledge_points.length; k++) {
                        results.push({
                            ...unit.knowledge_points[k],
                            unit: unit.name,
                            module: mod.name,
                            phase_name: unit.phase_name
                        });
                    }
                }
            }
        }
        return results;
    }
};

